const output = $input.first().json.output;

  // Si output ya es objeto, devolverlo directo
  if (typeof output === 'object') {
    return [{ json: output }];
  }

  // Intentar parsear JSON directamente (el agente debería devolver JSON puro)
  try {
    const parsed = JSON.parse(output);
    return [{ json: parsed }];
  } catch (_) {}

  // Fallback con regex para cada campo
  const messageMatch = output.match(/"response_message"\s*:\s*"((?:[^"\\]|\\.)*)"/);
  const queryMatch   = output.match(/"response_query"\s*:\s*"((?:[^"\\]|\\.|\n)*)"/);

  // response_chart es un objeto — extraer el bloque {} que le sigue
  let response_chart = null;
  const chartStart = output.indexOf('"response_chart"');
  if (chartStart !== -1) {
    const braceStart = output.indexOf('{', chartStart + 16);
    if (braceStart !== -1) {
      let depth = 0, i = braceStart;
      for (; i < output.length; i++) {
        if (output[i] === '{') depth++;
        else if (output[i] === '}') { depth--; if (depth === 0) break; }
      }
      try {
        response_chart = JSON.parse(output.slice(braceStart, i + 1));
      } catch (_) {}
    }
  }

  return [{
    json: {
      response_message: messageMatch ? messageMatch[1] : '',
      response_query:   queryMatch   ? queryMatch[1].replace(/\\n/g, '\n') : '',
      response_chart
    }
  }];

